'use client';

import { useEffect, useState } from 'react';
import { Button } from '@/components/atoms/Button';
import { Modal } from '@/components/molecules/Modal';
import { TextAreaBase } from '@/components/atoms/TextArea/TextArea';

export interface HtmlEmbedDialogProps {
  isOpen: boolean;
  initialHtml?: string;
  onSave: (html: string) => void;
  onClose: () => void;
  title?: string;
  'data-id'?: string;
}

export function HtmlEmbedDialog({
  isOpen,
  initialHtml = '',
  onSave,
  onClose,
  title = 'Edit HTML',
  'data-id': dataId = 'html-embed-dialog',
}: HtmlEmbedDialogProps) {
  const [value, setValue] = useState(initialHtml);

  useEffect(() => {
    if (isOpen) {
      setValue(initialHtml);
    }
  }, [isOpen, initialHtml]);

  const handleSave = () => {
    onSave(value);
    onClose();
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      size="md"
      withDividers
      data-id={dataId}
      actions={
        <>
          <Button
            color="secondary"
            onPress={onClose}
            data-id={`${dataId}-cancel`}
          >
            Cancel
          </Button>
          <Button
            color="primary"
            onPress={handleSave}
            data-id={`${dataId}-save`}
          >
            Save
          </Button>
        </>
      }
    >
      <TextAreaBase
        aria-label="Raw HTML"
        rows={10}
        value={value}
        onChange={(event) => setValue(event.target.value)}
        className="min-h-50 font-mono text-sm"
        placeholder="<iframe src='https://...' />"
      />
    </Modal>
  );
}
